    public PageReference resetAccount() {
        this.disableBillingTriggers();
        this.deleteDiscScheds();
        this.deletePaymentTransactions();
        this.deletePayments();
        this.deleteCreditNotes();
        this.deleteDebitNotes();
        this.deleteRefunds();
        this.deleteInvoices();
        this.deleteQuotes();
        this.deleteAssets();
