            String quoteJSON = SBQQ.ServiceRouter.save('SBQQ.QuoteAPI.QuoteSaver',
                    JSON.serialize(quote));
            return (QuoteModel) JSON.deserialize(quoteJSON, QuoteModel.class);
        }
    }

